### ClientProxy with Console Logging - NestJS Microservices

Source: https://github.com/nestjs/docs.nestjs.com/blob/master/content/microservices/custom-transport.md

Enhanced ClientProxy implementation that logs connection lifecycle, message dispatching, and teardown events with a 5-second delay simulation for response handling. Demonstrates proper callback execution with WritePacket containing response data and disposal flags.

```typescript
class GoogleCloudPubSubClient extends ClientProxy {
  async connect(): Promise<any> {
    console.log('connect');
  }

  async close() {
    console.log('close');
  }

  async dispatchEvent(packet: ReadPacket<any>): Promise<any> {
    return console.log('event to dispatch: ', packet);
  }

  publish(
    packet: ReadPacket<any>,
    callback: (packet: WritePacket<any>) => void,
  ): Function {
    console.log('message:', packet);

    setTimeout(() => callback({ 
      response: packet.data,
      isDisposed: true,
    }), 5000);

    return () => console.log('teardown');
  }

  unwrap<T = never>(): T {
    throw new Error('Method not implemented.');
  }
}
```

